                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <span>
                  第 {item.chapterStart} 章
                  {item.chapterEnd !== item.chapterStart && ` - 第 ${item.chapterEnd} 章`}
                </span>
                {isForeshadow && (
                  <Space size="small">
                    {['待回收', '铺设中', '已回收'].map(status => (
                      <Button
                        key={status}
                        size="small"
                        type="text"
                        style={{ fontSize: 11, padding: '0 4px', height: 20 }}
                        onClick={(e) => {
                          e.stopPropagation()
                          handleUpdateForeshadowStatus(item, status)
                        }}
                      >
                        {status}
                      </Button>
                    ))}
                  </Space>
                )}
              </div>
            </div>
          }
        />
      </List.Item>
    )
  }

  // 渲染伏笔看板
  const renderForeshadowBoard = () => {
    const statusColumns = [
      { key: '待铺设', title: '待铺设', color: '#ffa940' },
      { key: '铺设中', title: '铺设中', color: '#1890ff' },
      { key: '已铺设', title: '已铺设', color: '#52c41a' },
      { key: '待回收', title: '待回收', color: '#faad14' },
      { key: '已回收', title: '已回收', color: '#52c41a' },
    ]

    // 按状态分组
    const foreshadowsByStatus: Record<string, ForeshadowItem[]> = {}
    foreshadows.forEach(f => {
      const status = f.status || '待铺设'
      if (!foreshadowsByStatus[status]) {
        foreshadowsByStatus[status] = []
      }
      foreshadowsByStatus[status].push(f)
    })

    return (
      <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '10px 16px', borderBottom: '1px solid #e8e8e8' }}>
          <Space>
            <span>当前章节：</span>
            <InputNumber 
              size="small" 
              value={currentChapter} 
              onChange={(val) => setCurrentChapter(val || 1)}
              min={1}
              style={{ width: 80 }}
            />
            <Button size="small" onClick={loadForeshadows}>
              <ReloadOutlined />
            </Button>
          </Space>
        </div>

        <div style={{ flex: 1, overflow: 'auto', padding: '16px' }}>
          {foreshadowLoading ? (
            <div style={{ textAlign: 'center', padding: 40 }}>
              <Spin tip="加载伏笔数据中..." />
            </div>
          ) : foreshadows.length === 0 ? (
            <Empty description="暂无伏笔数据" />
          ) : (
            <Row gutter={16} style={{ height: '100%' }}>
              {statusColumns.map(col => {
                const items = foreshadowsByStatus[col.key] || []

                return (
                  <Col key={col.key} span={8} style={{ height: '100%' }}>
                    <Card 
                      size="small" 
                      title={
                        <div style={{ display: 'flex', alignItems: 'center' }}>
                          <div style={{
                            width: 8,
                            height: 8,
                            borderRadius: '50%',
                            backgroundColor: col.color,
                            marginRight: 8,
                          }} />
                          {col.title} ({items.length})
                        </div>
                      }
                      style={{ height: '100%' }}
                      bodyStyle={{ padding: '8px', overflow: 'auto', maxHeight: 'calc(100vh - 200px)' }}
                    >
                      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                        {items.map(item => {
                          // 检查是否需要标红（超过10章未回收）
                          const isOverdue = item.payoff_chapter && 
                            item.payoff_chapter > 0 && 
                            (item.payoff_chapter - currentChapter) > 10

                          return (
                            <Card
                              key={item.id}
                              size="small"
                              style={{
                                borderLeft: `3px solid ${col.color}`,
                                backgroundColor: isOverdue ? '#fff2f0' : '#fff',
                                borderColor: isOverdue ? '#ff4d4f' : col.color,
                              }}
                            >
                              <div style={{ fontSize: '12px' }}>
                                <div style={{ fontWeight: 500, marginBottom: 4 }}>
                                  {item.description}
                                </div>
                                <div style={{ color: '#666', marginBottom: 4 }}>
                                  <Tag size="small" color={col.color}>
                                    {item.type}
                                  </Tag>
                                  <span style={{ marginLeft: 4 }}>第{item.setup_chapter}章铺设</span>
                                  {item.payoff_chapter && (
                                    <span> · 第{item.payoff_chapter}章回收</span>
                                  )}
                                </div>
                                <div style={{ marginBottom: 4 }}>
                                  {item.related_characters.map(char => (
                                    <Tag key={char} size="small" style={{ marginRight: 4, marginBottom: 4 }}>
                                      {char}
                                    </Tag>
                                  ))}
                                </div>
                                {isOverdue && (
                                  <div style={{ color: '#ff4d4f', fontSize: '11px', marginBottom: 4 }}>
                                    ⚠️ 已超过{currentChapter}章未回收
                                  </div>
                                )}
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                  <span style={{ fontSize: '11px', color: '#999' }}>
                                    {item.id}
                                  </span>
                                  <Dropdown
                                    menu={{
                                      items: statusColumns.map(col => ({
                                        key: col.key,
                                        label: col.title,
                                      })),
                                      onClick: ({ key }) => updateForeshadowStatus(item.id, key),
                                    }}
                                  >
                                    <Button size="small" type="text">
                                      {item.status} <DownOutlined />
                                    </Button>
                                  </Dropdown>
                                </div>
                              </div>
                            </Card>
                          )
                        })}
                      </div>
                    </Card>
                  </Col>
                )
              })}
            </Row>
          )}
        </div>
      </div>
    )
  }"}]

